1	// Domain logic for MHPCO Claim Office
2	
3	export type ItemType = "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	export interface QuoteStep {
17	  op: "quote";
18	  items: Item[];
19	}
20	
21	export interface Damage {
22	  itemType: string;
23	  amount: number;
24	}
25	
26	export interface Incident {
27	  cause: string;
28	  damages: Damage[];
29	}
30	
31	export interface ClaimStep {
32	  op: "claim";
33	  policy: number;
34	  incident: Incident;
35	}
36	
37	export type Step = QuoteStep | ClaimStep;
38	
39	export interface Scenario {
40	  customer: Customer;
41	  steps: Step[];
42	}
43	
44	export interface QuoteResult {
45	  premium: number;
46	}
47	
48	export interface ClaimResult {
49	  payout: number;
50	  remainingCap: number;
51	}
52	
53	export type StepResult = QuoteResult | ClaimResult;
54	
55	export interface ScenarioOutput {
56	  results: StepResult[];
57	}
58	
59	const MAIN_ITEMS: Record<string, { value: number; premium: number }> = {
60	  sword: { value: 1000, premium: 100 },
61	  amulet: { value: 600, premium: 60 },
62	  staff: { value: 800, premium: 80 },
63	  potion: { value: 400, premium: 40 },
64	};
65	
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	const COMPONENT_VALUE = 250;
68	const COMPONENT_PREMIUM = 25;
69	const COMPONENT_BLOCK_PREMIUM = 60;
70	const COMPONENT_BLOCK_SIZE = 3;
71	
72	const DEDUCTIBLE = 100;
73	const PROCESSING_FEE = 5;
74	
75	function isMainItem(type: string): boolean {
76	  return type in MAIN_ITEMS;
77	}
78	
79	function isComponent(type: string): boolean {
80	  return COMPONENT_TYPES.has(type);
81	}
82	
83	export function validateItems(items: Item[]): void {
84	  for (const item of items) {
85	    if (!isMainItem(item.type) && !isComponent(item.type)) {
86	      throw new Error(`Unknown item type: ${item.type}`);
87	    }
88	  }
89	}
90	
91	export function insuranceValue(item: Item): number {
92	  if (isMainItem(item.type)) return MAIN_ITEMS[item.type].value;
93	  if (isComponent(item.type)) return COMPONENT_VALUE;
94	  throw new Error(`Unknown item type: ${item.type}`);
95	}
96	
97	export function policyInsuranceSum(items: Item[]): number {
98	  return items.reduce((sum, it) => sum + insuranceValue(it), 0);
99	}
100	
101	// Computes the base premium contribution per item, taking into account block discounts for components.
102	// Returns an array aligned with items.
103	function itemBasePremiums(items: Item[]): number[] {
104	  // For main items, base premium is straightforward.
105	  // For components, group by type and apply block discount.
106	  const result: number[] = new Array(items.length).fill(0);
107	
108	  // collect indices grouped by component type
109	  const componentIndicesByType: Record<string, number[]> = {};
110	
111	  for (let i = 0; i < items.length; i++) {
112	    const item = items[i];
113	    if (isMainItem(item.type)) {
114	      result[i] = MAIN_ITEMS[item.type].premium;
115	    } else if (isComponent(item.type)) {
116	      if (!componentIndicesByType[item.type]) componentIndicesByType[item.type] = [];
117	      componentIndicesByType[item.type].push(i);
118	    }
119	  }
120	
121	  for (const type of Object.keys(componentIndicesByType)) {
122	    const indices = componentIndicesByType[type];
123	    const count = indices.length;
124	    // Block applies only when count is exactly 3.
125	    const groupTotal = count === COMPONENT_BLOCK_SIZE
126	      ? COMPONENT_BLOCK_PREMIUM
127	      : count * COMPONENT_PREMIUM;
128	    const perItem = groupTotal / count;
129	    for (const idx of indices) {
130	      result[idx] = perItem;
131	    }
132	  }
133	
134	  return result;
135	}
136	
137	function itemSurcharge(item: Item, basePremium: number): number {
138	  let surcharge = 0;
139	  if (item.cursed) surcharge += basePremium * 0.5;
140	  if (typeof item.enchantment === "number" && item.enchantment >= 5) surcharge += basePremium * 0.3;
141	  return surcharge;
142	}
143	
144	export interface QuoteContext {
145	  yearsWithMHPCO: number;
146	  isFollowUpContract: boolean; // true when this quote is not the customer's first
147	}
148	
149	function roundUp(value: number): number {
150	  // round up to whole G (favor MHPCO for premiums)
151	  return Math.ceil(value - 1e-9);
152	}
153	
154	function roundDown(value: number): number {
155	  // round down to whole G (favor MHPCO for payouts)
156	  return Math.floor(value + 1e-9);
157	}
158	
159	export function computePremium(items: Item[], context: QuoteContext): number {
160	  validateItems(items);
161	
162	  const basePremiums = itemBasePremiums(items);
163	  const policyBase = basePremiums.reduce((a, b) => a + b, 0);
164	
165	  // Item-level surcharges
166	  let itemSurcharges = 0;
167	  for (let i = 0; i < items.length; i++) {
168	    itemSurcharges += itemSurcharge(items[i], basePremiums[i]);
169	  }
170	
171	  // Policy-wide modifiers apply to the policy base premium
172	  let policyModifiers = 0;
173	  if (context.yearsWithMHPCO >= 2) policyModifiers -= policyBase * 0.2; // loyalty discount
174	  // First insurance surcharge - 10 % per item (each item treated as first insurance)
175	  // Per spec: "each item in a `quote` is treated as a first insurance"
176	  // Apply 10% surcharge to each item's base premium.
177	  let firstInsuranceSurcharge = 0;
178	  for (let i = 0; i < items.length; i++) {
179	    firstInsuranceSurcharge += basePremiums[i] * 0.1;
180	  }
181	
182	  if (context.isFollowUpContract) policyModifiers -= policyBase * 0.15;
183	
184	  const subtotal = policyBase + itemSurcharges + policyModifiers + firstInsuranceSurcharge;
185	  const withFee = subtotal + PROCESSING_FEE;
186	
187	  return roundUp(withFee);
188	}
189	
190	export interface PolicyState {
191	  items: Item[];
192	  insuranceSum: number;
193	  cap: number;
194	  remainingCap: number;
195	}
196	
197	export function createPolicy(items: Item[]): PolicyState {
198	  validateItems(items);
199	  const insuranceSum = policyInsuranceSum(items);
200	  const cap = insuranceSum * 2;
201	  return { items, insuranceSum, cap, remainingCap: cap };
202	}
203	
204	function isDragonMaterial(item: Item): boolean {
205	  return item.material === "dragon";
206	}
207	
208	function isHighlyEnchanted(item: Item): boolean {
209	  return typeof item.enchantment === "number" && item.enchantment >= 8;
210	}
211	
212	export function processClaim(policy: PolicyState, incident: Incident): ClaimResult {
213	  // Validate damages: each damage must correspond to an item in the policy.
214	  // Multiple entries of the same type require sufficient covered items.
215	  const itemsByType: Record<string, Item[]> = {};
216	  for (const it of policy.items) {
217	    if (!itemsByType[it.type]) itemsByType[it.type] = [];
218	    itemsByType[it.type].push(it);
219	  }
220	
221	  // Validate negative amounts and unknown types
222	  for (const d of incident.damages) {
223	    if (d.amount < 0) {
224	      throw new Error(`Negative damage amount not allowed: ${d.amount}`);
225	    }
226	    if (!isMainItem(d.itemType) && !isComponent(d.itemType)) {
227	      throw new Error(`Unknown damage item type: ${d.itemType}`);
228	    }
229	  }
230	
231	  // Pair damages with items, consuming each item once.
232	  const consumed: Record<string, number> = {};
233	  const pairings: { item: Item; amount: number }[] = [];
234	  for (const d of incident.damages) {
235	    const list = itemsByType[d.itemType] || [];
236	    const used = consumed[d.itemType] || 0;
237	    if (used >= list.length) {
238	      throw new Error(`Damage refers to item not in policy: ${d.itemType}`);
239	    }
240	    pairings.push({ item: list[used], amount: d.amount });
241	    consumed[d.itemType] = used + 1;
242	  }
243	
244	  let totalPayout = 0;
245	  for (const { item, amount } of pairings) {
246	    let damage = amount;
247	    // High-enchantment (>=8) clause wins over dragon-material clause
248	    if (isHighlyEnchanted(item)) {
249	      damage = amount * 0.5;
250	    } else if (isDragonMaterial(item)) {
251	      damage = amount;
252	    }
253	    const afterDeductible = Math.max(0, damage - DEDUCTIBLE);
254	    totalPayout += afterDeductible;
255	  }
256	
257	  const rounded = roundDown(totalPayout);
258	  const capped = Math.min(rounded, policy.remainingCap);
259	  policy.remainingCap -= capped;
260	  return { payout: capped, remainingCap: policy.remainingCap };
261	}
262	
263	export function runScenario(scenario: Scenario): ScenarioOutput {
264	  const results: StepResult[] = [];
265	  const policies: Record<number, PolicyState> = {};
266	  let quoteCount = 0;
267	
268	  for (let i = 0; i < scenario.steps.length; i++) {
269	    const step = scenario.steps[i];
270	    if (step.op === "quote") {
271	      const isFollowUp = quoteCount > 0;
272	      const premium = computePremium(step.items, {
273	        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
274	        isFollowUpContract: isFollowUp,
275	      });
276	      results.push({ premium });
277	      policies[i] = createPolicy(step.items);
278	      quoteCount++;
279	    } else if (step.op === "claim") {
280	      const policy = policies[step.policy];
281	      if (!policy) {
282	        throw new Error(`Claim references unknown policy index: ${step.policy}`);
283	      }
284	      const result = processClaim(policy, step.incident);
285	      results.push(result);
286	    } else {
287	      throw new Error(`Unknown operation`);
288	    }
289	  }
290	
291	  return { results };
292	}
