59	const MAIN_ITEMS: Record<string, { value: number; premium: number }> = {
60	  sword: { value: 1000, premium: 100 },
61	  amulet: { value: 600, premium: 60 },
62	  staff: { value: 800, premium: 80 },
63	  potion: { value: 400, premium: 40 },
64	};
65	
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	const COMPONENT_VALUE = 250;
68	const COMPONENT_PREMIUM = 25;
69	const COMPONENT_BLOCK_PREMIUM = 60;
70	const COMPONENT_BLOCK_SIZE = 3;
71	
72	const DEDUCTIBLE = 100;
73	const PROCESSING_FEE = 5;
74	
75	function isMainItem(type: string): boolean {
76	  return type in MAIN_ITEMS;
77	}
78	
79	function isComponent(type: string): boolean {
80	  return COMPONENT_TYPES.has(type);
81	}
82	
83	export function validateItems(items: Item[]): void {
84	  for (const item of items) {
85	    if (!isMainItem(item.type) && !isComponent(item.type)) {
86	      throw new Error(`Unknown item type: ${item.type}`);
87	    }
88	  }
89	}
90	
91	export function insuranceValue(item: Item): number {
92	  if (isMainItem(item.type)) return MAIN_ITEMS[item.type].value;
93	  if (isComponent(item.type)) return COMPONENT_VALUE;
94	  throw new Error(`Unknown item type: ${item.type}`);
95	}
96	
97	export function policyInsuranceSum(items: Item[]): number {
98	  return sum(items.map(insuranceValue));
99	}
100	
101	// Per-type count of components in the policy, used for the block discount.
102	function countComponentsByType(items: Item[]): Record<string, number> {
103	  const counts: Record<string, number> = {};
104	  for (const item of items) {
105	    if (isComponent(item.type)) {
106	      counts[item.type] = (counts[item.type] ?? 0) + 1;
107	    }
108	  }
109	  return counts;
110	}
111	
112	// Base premium contribution of one item, aware of the block discount that
113	// applies when a component type appears exactly COMPONENT_BLOCK_SIZE times.
114	function basePremiumFor(item: Item, componentCountForType: number): number {
115	  if (isMainItem(item.type)) return MAIN_ITEMS[item.type].premium;
116	  const blockApplies = componentCountForType === COMPONENT_BLOCK_SIZE;
117	  const groupTotal = blockApplies ? COMPONENT_BLOCK_PREMIUM : componentCountForType * COMPONENT_PREMIUM;
118	  return groupTotal / componentCountForType;
119	}
120	
121	// Returns the base premium per item, aligned with items.
122	function itemBasePremiums(items: Item[]): number[] {
123	  const componentCounts = countComponentsByType(items);
124	  return items.map((item) => basePremiumFor(item, componentCounts[item.type] ?? 0));
125	}
126	
127	function itemSurcharge(item: Item, basePremium: number): number {
128	  let surcharge = 0;
129	  if (item.cursed) surcharge += basePremium * 0.5;
130	  if (typeof item.enchantment === "number" && item.enchantment >= 5) surcharge += basePremium * 0.3;
131	  return surcharge;
132	}
133	
134	export interface QuoteContext {
135	  yearsWithMHPCO: number;
136	  isFollowUpContract: boolean; // true when this quote is not the customer's first
137	}
138	
139	function roundUp(value: number): number {
140	  // round up to whole G (favor MHPCO for premiums)
141	  return Math.ceil(value - 1e-9);
142	}
143	
144	function roundDown(value: number): number {
145	  // round down to whole G (favor MHPCO for payouts)
146	  return Math.floor(value + 1e-9);
147	}
148	
149	const LOYALTY_YEARS_THRESHOLD = 2;
150	const LOYALTY_DISCOUNT_RATE = 0.2;
151	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
152	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
153	
154	export function computePremium(items: Item[], context: QuoteContext): number {
155	  validateItems(items);
156	
157	  const basePremiums = itemBasePremiums(items);
158	  const policyBase = sum(basePremiums);
159	  const itemSurcharges = sum(items.map((item, i) => itemSurcharge(item, basePremiums[i])));
160	
161	  // Policy-wide modifiers applied to the policy base premium.
162	  // Per spec, each item in a quote is treated as a first insurance,
163	  // so the 10% first-insurance surcharge sums to 10% of the policy base.
164	  const loyaltyDiscount =
165	    context.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
166	  const followUpDiscount = context.isFollowUpContract ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
167	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
168	
169	  const subtotal =
170	    policyBase + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount;
171	
172	  return roundUp(subtotal + PROCESSING_FEE);
173	}
174	
175	function sum(values: number[]): number {
176	  return values.reduce((a, b) => a + b, 0);
177	}
178	
179	export interface PolicyState {
180	  items: Item[];
181	  insuranceSum: number;
182	  cap: number;
183	  remainingCap: number;
184	}
185	
186	export function createPolicy(items: Item[]): PolicyState {
187	  validateItems(items);
188	  const insuranceSum = policyInsuranceSum(items);
189	  const cap = insuranceSum * 2;
190	  return { items, insuranceSum, cap, remainingCap: cap };
191	}
192	
193	function isHighlyEnchanted(item: Item): boolean {
194	  return typeof item.enchantment === "number" && item.enchantment >= 8;
195	}
196	
197	function groupItemsByType(items: Item[]): Record<string, Item[]> {
198	  const byType: Record<string, Item[]> = {};
199	  for (const item of items) {
200	    (byType[item.type] ??= []).push(item);
201	  }
202	  return byType;
203	}
204	
205	function validateDamage(damage: Damage): void {
206	  if (damage.amount < 0) {
207	    throw new Error(`Negative damage amount not allowed: ${damage.amount}`);
208	  }
209	  if (!isMainItem(damage.itemType) && !isComponent(damage.itemType)) {
210	    throw new Error(`Unknown damage item type: ${damage.itemType}`);
211	  }
212	}
213	
214	// Pairs each damage entry with the next available item of that type, treating
215	// repeat damages of the same type as separate items in the policy.
216	function pairDamagesWithItems(
217	  damages: Damage[],
218	  itemsByType: Record<string, Item[]>,
219	): { item: Item; amount: number }[] {
220	  const consumed: Record<string, number> = {};
221	  return damages.map((damage) => {
222	    const available = itemsByType[damage.itemType] ?? [];
223	    const used = consumed[damage.itemType] ?? 0;
224	    if (used >= available.length) {
225	      throw new Error(`Damage refers to item not in policy: ${damage.itemType}`);
226	    }
227	    consumed[damage.itemType] = used + 1;
228	    return { item: available[used], amount: damage.amount };
229	  });
230	}
231	
232	// Per spec, the high-enchantment (>=8) clause halves the damage and wins
233	// over the dragon-material clause (which by itself does not change the
234	// damage figure — only the deductible reduces the final payout).
235	function payoutForPairing(item: Item, amount: number): number {
236	  const damage = isHighlyEnchanted(item) ? amount * 0.5 : amount;
237	  return Math.max(0, damage - DEDUCTIBLE);
238	}
239	
240	export function processClaim(policy: PolicyState, incident: Incident): ClaimResult {
241	  incident.damages.forEach(validateDamage);
242	
243	  const pairings = pairDamagesWithItems(incident.damages, groupItemsByType(policy.items));
244	
245	  const totalPayout = pairings.reduce(
246	    (sum, { item, amount }) => sum + payoutForPairing(item, amount),
247	    0,
248	  );
249	
250	  const capped = Math.min(roundDown(totalPayout), policy.remainingCap);
251	  policy.remainingCap -= capped;
252	  return { payout: capped, remainingCap: policy.remainingCap };
253	}
254	
255	export function runScenario(scenario: Scenario): ScenarioOutput {
256	  const policies: Record<number, PolicyState> = {};
257	  const results: StepResult[] = [];
258	
259	  scenario.steps.forEach((step, stepIndex) => {
260	    if (step.op === "quote") {
261	      const isFollowUpContract = Object.keys(policies).length > 0;
262	      results.push({
263	        premium: computePremium(step.items, {
264	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
265	          isFollowUpContract,
266	        }),
267	      });
268	      policies[stepIndex] = createPolicy(step.items);
269	      return;
270	    }
271	    if (step.op === "claim") {
272	      const policy = policies[step.policy];
273	      if (!policy) {
274	        throw new Error(`Claim references unknown policy index: ${step.policy}`);
275	      }
276	      results.push(processClaim(policy, step.incident));
277	      return;
278	    }
279	    throw new Error(`Unknown operation`);
280	  });
281	
282	  return { results };
283	}
